1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Array<Item> };
13	type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Array<Step>;
16	};
17	
18	const itemPremium = (item: Item): number => {
19	  const base = BASE_PREMIUM[item.type];
20	  return base + base * FIRST_INSURANCE_RATE;
21	};
22	
23	const sumItemPremiums = (items: Array<Item>): number =>
24	  items.reduce((total, item) => total + itemPremium(item), 0);
25	
26	const quotePremium = ({ items }: Step): number =>
27	  sumItemPremiums(items) + PROCESSING_FEE;
28	
29	export const runScenario = (scenario: unknown): unknown => {
30	  const { steps } = scenario as Scenario;
31	  return {
32	    results: steps.map((step) => ({ premium: quotePremium(step) })),
33	  };
34	};
35

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge case: empty items
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type (single item, no modifiers, newcomer 0 years, first contract)
15	  // With 0 years (no loyalty), first contract = no follow-up discount but the spec says
16	  // "each item in a quote is treated as a first insurance", so +10% per item applies.
17	  // For pure base premium tests we use multi-step or rely on the integration example math.
18	  // Simpler: test the single-item quote with newcomer 0 years, no curse, low enchantment.
19	
20	  // We'll test via runScenario (the top-level entry point).
21	  it("quote a plain sword for newcomer (0 yrs, 1st contract) → 100 base + 10 first ins + 5 fee = 115 G", () => {
22	    const result = runScenario({
23	      customer: { yearsWithMHPCO: 0 },
24	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
25	    });
26	    expect(result).toEqual({ results: [{ premium: 115 }] });
27	  });
28	  it("quote a plain amulet for newcomer → 60 + 6 + 5 = 71 G", () => {
29	    const result = runScenario({
30	      customer: { yearsWithMHPCO: 0 },
31	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }] }],
32	    });
33	    expect(result).toEqual({ results: [{ premium: 71 }] });
34	  });
35	  it("quote a plain staff for newcomer → 80 + 8 + 5 = 93 G", () => {
36	    const result = runScenario({
37	      customer: { yearsWithMHPCO: 0 },
38	      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }] }],
39	    });
40	    expect(result).toEqual({ results: [{ premium: 93 }] });
41	  });
42	  it("quote a plain potion for newcomer → 40 + 4 + 5 = 49 G", () => {
43	    const result = runScenario({
44	      customer: { yearsWithMHPCO: 0 },
45	      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }] }],
46	    });
47	    expect(result).toEqual({ results: [{ premium: 49 }] });
48	  });
49	
50	  // Components
51	  it.todo("quote 1 rune for newcomer → 25 + 2.5 first ins = 27.5 → 28 + 5 = 33 G (rounded up in MHPCO favor)");
52	  it.todo("quote 2 runes for newcomer → 50 base + 5 first ins = 55 + 5 = 60 G");
53	
54	  // Block discount
55	  it.todo("3 runes form a block → 60 base premium (block applies)");
56	  it.todo("4 runes → 100 base premium (no block — block requires exactly 3)");
57	  it.todo("7 runes → 175 base premium (one block of 3 = 60, plus 4 individual = 100)");
58	
59	  // Alike-components clarification
60	  it.todo("2 runes + 1 moonstone → 75 base premium (no block: different types)");
61	  it.todo("3 runes + 3 moonstones → 120 base premium (two separate blocks)");
62	
63	  // Modifier thresholds
64	  it.todo("customer with exactly 2 years gets loyalty discount");
65	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
66	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
67	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
68	
69	  // Modifier scope on multi-item policies
70	  it.todo("policy with cursed sword + plain amulet → curse surcharge applies only to sword's base (210 G before fee)");
71	
72	  // Rounding in MHPCO's favor
73	  it.todo("premium 197.5 G → rounded up to 198 G");
74	  it.todo("payout 350.5 G → rounded down to 350 G");
75	
76	  // Integration: Newcomer with a cursed sword
77	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
78	
79	  // Integration: Long-standing customer's second contract
80	  it.todo("3-yr customer's 2nd contract, cursed sword enchantment 7 → 160 G");
81	
82	  // Claim processing — standard reimbursement
83	  it.todo("regular sword, damage 500 G → payout 400 G (full minus 100 deductible)");
84	  it.todo("rune damage 200 G → payout 100 G (no special clause, minus deductible)");
85	
86	  // Claim — high enchantment clause
87	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
88	
89	  // Claim — dragon material
90	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full, then deductible)");
91	
92	  // Claim — both clauses (enchantment wins precedence-ordered with 50% then deductible)
93	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G");
94	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G → payout 400 G");
95	
96	  // Claim — deductible per damage event (per item)
97	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");
98	
99	  // Multiple items of same type
100	  it.todo("policy covers 2 swords → insurance sum 2000, cap 4000");
101	  it.todo("two swords policy, damages list two sword entries → each treated as separate damage with own deductible");
102	  it.todo("damages has more entries of a type than insured → CLI rejects (non-zero exit)");
103	
104	  // Cap exhaustion
105	  it.todo("sword+amulet policy → insurance sum 1600 G, cap 3200 G");
106	  it.todo("cursed sword → cap based on unmodified insurance value (2000 G)");
107	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");
108	  it.todo("successive claims on sword (cap 2000): first 1500→pay 1400 cap 600, second 1500→pay 600 cap 0");
109	
110	  // CLI error handling (these are exercised via the CLI, but logic can return errors)
111	  it.todo("quote with unknown item type → CLI exits non-zero with stderr error");
112	  it.todo("claim references damage for item not in policy → CLI exits non-zero");
113	  it.todo("claim damage with negative amount → CLI exits non-zero");
114	});
